qry:select.qry:xquery:
	for $r in sql('
	SELECT 
		REN.oi_rendicion, 
		REN.f_rendicion,
		SUJ.c_sujeto,
		SUJ.d_sujeto,
		REN.l_anulado, 
		REN.n_monto_rendicion, 
		REN.o_rendicion, 
		REN.oi_adelanto,					
		ADE.f_adelanto,
		ADE.n_monto_adel,
		CAR.c_carpeta,
		CAR.d_carpeta,
		EMP.c_empresa,
		EMP.d_empresa
	FROM
		LEG06_RENDICIONES AS REN,					 
		LEG04_ADELANTOS as ADE,
		LEG40_CLASIF_SUJ as CLA,
		LEG40_SUJETOS as SUJ,
		LEG01_CARPETAS as CAR,
		ORG03_EMPRESAS as EMP

	JOIN
		EMP.oi_empresa INNER CAR.oi_empresa,
		REN.oi_adelanto INNER ADE.oi_adelanto,					
		ADE.oi_carpeta INNER CAR.oi_carpeta,
		ADE.oi_clasif_sujeto INNER CLA.oi_clasif_sujeto,
		CLA.oi_sujeto INNER SUJ.oi_sujeto
	WHERE
		CAR.oi_estado_carpeta!=11 AND
		CAR.oi_carpeta IN ({%=$PARAM/@oi_carpeta%})
		{%? (#FILTRO:@oi_empresa!='')                  
			{% AND CAR.oi_empresa = {#FILTRO:@oi_empresa} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_carpeta!='')                  
			{% AND ADE.oi_carpeta = {#FILTRO:@oi_carpeta} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_clasif_sujeto!='')                  
			{% AND ADE.oi_clasif_sujeto = {#FILTRO:@oi_clasif_sujeto} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_ubicacion!='')                  
			{% AND ADE.oi_ubicacion = {#FILTRO:@oi_ubicacion} %}
			{% %} 
		%}
		{%? (#FILTRO:@oi_adelanto!='')                  
			{% AND ADE.oi_adelanto = {#FILTRO:@oi_adelanto} %}
			{% %} 
		%}
		{%? (#FILTRO:@l_anulados!='1')                  
			{% AND REN.l_anulado = \'0\' %}
			{% %} 
		%}
		{%?(#FILTRO:@f_tarea_d!='') 
			{% AND REN.f_rendicion >= {#FILTRO:@f_tarea_d} %} 
			{% %} 
		%}
		{%?(#FILTRO:@f_tarea_h!='') 
			{% AND REN.f_rendicion <  {Datetime(Number(Datetime(#FILTRO:@f_tarea_h))+1)} %} 
			{% %} 
		%}
	ORDER BY f_rendicion ASC
')/ROWS/ROW
